package com.ling.linginnerflow.rag;

import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.boot.ApplicationArguments;
import org.springframework.boot.ApplicationRunner;
import org.springframework.stereotype.Component;

import java.util.LinkedHashMap;
import java.util.Map;

/**
 * CBT知识库初始化器
 * 项目启动时自动把CBT内容同时上传到：
 * 1. Pinecone（向量检索）
 * 2. Elasticsearch（关键词检索）
 */
@Slf4j
@Component
@RequiredArgsConstructor
public class CBTDataInitializer implements ApplicationRunner {

    private final CBTKnowledgeService cbtKnowledgeService;
    private final CBTDocumentRepository cbtDocumentRepository;

    @Override
    public void run(ApplicationArguments args) throws Exception {
        log.info("Initializing CBT knowledge base...");

        long esCount = cbtDocumentRepository.count();
        if (esCount > 0) {
            log.info("ES already has {} entries, skipping initialization.", esCount);
            return;
        }

        Map<String, String> cbtData = buildCBTData();

        int pineconeSuccess = 0;
        int esSuccess = 0;

        for (Map.Entry<String, String> entry : cbtData.entrySet()) {
            String id = entry.getKey();
            String text = entry.getValue();

            try {
                cbtKnowledgeService.upsertCBTContent(id, text);
                pineconeSuccess++;
                Thread.sleep(500);
            } catch (Exception e) {
                log.error("Pinecone upload failed: id={}", id);
            }

            try {
                CBTDocument doc = new CBTDocument();
                doc.setId(id);
                doc.setContent(text);
                doc.setCategory(extractCategory(id));
                cbtDocumentRepository.save(doc);
                esSuccess++;
            } catch (Exception e) {
                log.error("ES write failed: id={}", id);
            }
        }

        log.info("CBT knowledge base initialized. Pinecone: {}/{}, ES: {}/{}",
                pineconeSuccess, cbtData.size(), esSuccess, cbtData.size());
    }

    private String extractCategory(String id) {
        int num = Integer.parseInt(id.replace("CBT-", ""));
        if (num <= 40)  return "Cognitive Distortions";
        if (num <= 80)  return "Challenging Negative Thoughts";
        if (num <= 120) return "Emotion Regulation";
        if (num <= 150) return "Behavioral Activation";
        if (num <= 170) return "Anxiety Management";
        return "Self-Compassion & Core Beliefs";
    }

    private Map<String, String> buildCBTData() {
        Map<String, String> data = new LinkedHashMap<>();

        data.put("CBT-001", "【All-or-Nothing Thinking】This distortion is also known as black-and-white thinking. It is the tendency to see things in extremes, where you are either a total success or a complete failure with no middle ground. You can identify this by looking for words like always, never, or impossible in your self-talk. To apply a fix, try to find the gray area. If a project wasn't perfect, remind yourself that it still had strong points and served its purpose. Life exists in percentages, not just zeros and ones, so acknowledging partial success can really lower your stress levels.");
        data.put("CBT-002", "【Catastrophizing】Catastrophizing happens when you jump to the worst possible conclusion, turning a small bump in the road into a total disaster. You might think that a single mistake at work will lead to getting fired and ending up homeless. To spot this, ask yourself if you are treating a possibility as a certainty. To handle it, try to play out the most likely scenario instead of the worst one. Remind yourself that even if things go wrong, you have the skills to cope and find a solution. Breaking the cycle starts with realizing you are stronger than your fears.");
        data.put("CBT-003", "【Mind Reading】This is when you assume you know what others are thinking without any real proof. You might see someone look away and decide they find you boring or annoying. You can identify mind reading by noticing when you act based on an imagined thought in someone else's head. To apply a different approach, remind yourself that you aren't a psychic. People have a million things on their minds that have nothing to do with you. If you're unsure, try asking them directly or just let the thought pass without giving it power over your mood.");
        data.put("CBT-004", "【Emotional Reasoning】Emotional reasoning is the belief that because you feel a certain way, it must be true. For example, if you feel guilty, you conclude you must have done something wrong, even if there is no evidence. You can identify this by the phrase I feel, therefore I am. To apply a shift, remember that feelings are like weather—they change and aren't always facts. When a strong emotion hits, pause and look for objective evidence. Validating your feelings while questioning their accuracy helps you stay grounded in reality rather than being swept away by a temporary mood.");
        data.put("CBT-005", "【Mental Filtering】This happens when you focus exclusively on one negative detail while ignoring all the positive things that happened. It is like wearing glasses that only let dark light through. You might get a great performance review but spend the whole day obsessing over one tiny suggestion for improvement. To identify filtering, look for times you dismiss your wins as luck. To apply a change, intentionally look for at least three positive things to balance out the negative one. This isn't about ignoring problems, but about seeing the whole picture so you don't feel unnecessarily defeated.");
        data.put("CBT-006", "【Should Statements】Using words like should, must, or ought to creates a lot of unnecessary pressure and guilt. You might tell yourself I should be more productive or I must never make mistakes. Identify this by the heavy feeling of obligation in your thoughts. To apply a healthier mindset, try replacing should with I would like to or it would be helpful if. This shifts the focus from a rigid rule to a flexible preference. Being kinder to yourself reduces the rebellion we often feel when we try to force ourselves into a perfect, unattainable standard.");
        data.put("CBT-007", "【Labeling】Labeling is an extreme form of overgeneralization where you assign a global negative trait to yourself based on a single event. Instead of saying I made a mistake, you say I am a loser. You can identify this by noticing when you define your entire worth by one action. To apply a fix, focus on the behavior rather than the person. You are a complex human being, not a static label. Recognizing that your actions don't define your essence allows you to learn from failures without damaging your core self-esteem and confidence.");
        data.put("CBT-008", "【Personalization】This is when you take responsibility for things that are not actually your fault or are outside your control. You might blame yourself for a friend's bad mood or a project failing due to budget cuts. Identify this by noticing if you use the word I for situations involving many people. To apply a change, practice looking at all the factors involved. Often, other people's reactions are about their own stress and history, not you. Recognizing the boundary between your actions and external events brings a huge sense of relief and emotional freedom.");
        data.put("CBT-009", "【Overgeneralization】Overgeneralization is taking a single negative event and seeing it as a never-ending pattern of defeat. If you go on one bad date, you might think I will be alone forever. You can identify this by the words always and never appearing in your thoughts about the future. To apply a correction, look at the specific event as an isolated incident. Remind yourself that one bad outcome doesn't dictate what will happen next time. By narrowing your focus to the present moment, you stop a small setback from turning into a heavy, hopeless narrative about your life.");
        data.put("CBT-010", "【Magnification】This involves blowing things out of proportion, making your problems seem much larger than they actually are. It is the opposite of seeing the big picture. You might think a small typo in an email is a sign of total incompetence. Identify this by the intense anxiety that follows a minor slip-up. To apply a fix, ask yourself if this will matter in five years, or even five weeks. Putting the event into a larger timeline helps shrink the problem back down to its actual size, making it much easier to handle and move past.");
        data.put("CBT-011", "【Minimization】Minimization happens when you shrink your positive qualities or successes until they seem tiny and unimportant. When someone compliments you, you might think they are just being nice or that anyone could have done it. Identify this by the way you brush off achievements. To apply a change, practice simply saying thank you and letting the success sit with you for a moment. Acknowledge your hard work and skills. Giving yourself credit isn't arrogant; it's an honest assessment of your abilities that builds the resilience you need for future challenges.");
        data.put("CBT-012", "【Jumping to Conclusions】This distortion involves making a negative interpretation even though there are no definite facts that convincingly support your conclusion. It usually takes the form of mind reading or fortune telling. You can identify this when you feel certain about an outcome before it even happens. To apply a more balanced view, treat your thoughts as hypotheses rather than facts. Ask yourself what other possibilities exist. By waiting for actual evidence before reacting, you save yourself a lot of emotional energy and prevent unnecessary conflict with others or within your own mind.");
        data.put("CBT-013", "【The Mental Filter】Imagine your mind is a colander that only catches the lumps and lets the smooth liquid through. That is the mental filter. You focus on the one critical comment in a sea of praise. You can identify this when you feel discouraged despite having many reasons to feel good. To apply a fix, try to widen your filter. Actively search for the positives you might be letting slip through. Keeping a gratitude journal or a list of daily wins can help retrain your brain to notice the good stuff that is already there.");
        data.put("CBT-014", "【Disqualifying the Positive】This is a step beyond filtering; it’s actively turning a positive experience into a negative one. If you do a good job, you tell yourself it doesn't count because it was too easy. Identify this by the word but following every compliment you receive. To apply a new habit, try to stop at the compliment. Don't let your brain add the but. Accepting that you did something well, regardless of the circumstances, helps build a more accurate and positive self-image over time, replacing the habit of self-sabotage with self-support.");
        data.put("CBT-015", "【Fortune Telling】Fortune telling is when you predict that things will turn out badly before they even start. You might tell yourself that a party will be awkward, so you decide not to go. You can identify this by noticing when you feel hopeless about the future. To apply a correction, remind yourself that the future is unwritten. You don't have a crystal ball. Instead of predicting failure, try to stay curious about what might actually happen. Shifting from a mindset of certainty to one of curiosity can significantly reduce your pre-event anxiety and openness to joy.");
        data.put("CBT-016", "【Comparison Trap】The comparison trap is when you compare your inner struggles with everyone else's outer highlights. You see people on social media looking perfect and decide you are falling behind. Identify this by feelings of inadequacy after looking at others. To apply a fix, remind yourself that you are comparing your behind-the-scenes footage with their highlight reel. Everyone has struggles you can't see. Focus on your own progress and values rather than an imaginary competition. Your journey is unique, and your only real benchmark should be who you were yesterday, not who someone else appears to be.");
        data.put("CBT-017", "【Self-Blame】Self-blame is a form of personalization where you take the fall for things that aren't your fault. You might think it's your fault a meeting was boring or a relative is unhappy. Identify this by a constant feeling of guilt for things outside your influence. To apply a fix, draw a circle of control. Inside, put your actions and words. Outside, put other people's feelings and external events. If it's outside the circle, it's not yours to carry. Letting go of this false responsibility allows you to focus your energy where it actually matters.");
        data.put("CBT-018", "【Control Fallacies】This distortion can go two ways: feeling you have no control over your life, or feeling you must control everything. You might feel like a victim of fate or feel responsible for everyone's happiness. Identify this by feelings of helplessness or extreme burnout. To apply a shift, look for the middle path. You can't control everything, but you can always control your response to what happens. Identifying small areas where you do have agency can help you feel empowered without the crushing weight of trying to manage the entire world around you.");
        data.put("CBT-019", "【Fallacy of Fairness】This is the idea that life should always be fair and you feel resentful when it isn't. You might think I worked harder, so I should have gotten the promotion. Identify this by feelings of bitterness or anger when things don't go as expected. To apply a change, try to accept that fairness is a human concept, not a law of the universe. While it is okay to advocate for yourself, holding onto resentment about unfairness only hurts you. Focus on what you can do moving forward rather than getting stuck in why things weren't fair.");
        data.put("CBT-020", "【Fallacy of Change】This is the belief that you can only be happy if other people change their behavior. You might pressure a partner or friend to act differently so you can feel secure. Identify this by the thought If they would just do X, then I would be fine. To apply a fix, focus on your own self-regulation. You are the only person you can truly change. Finding ways to meet your own needs and set healthy boundaries, regardless of how others act, gives you back your power and leads to much more stable happiness.");
        data.put("CBT-021", "【Always Being Right】This distortion makes the idea of being wrong unacceptable. You will go to great lengths to prove your point, even if it hurts your relationships. Identify this by noticing if you prioritize winning an argument over the feelings of the person you are talking to. To apply a shift, ask yourself: would I rather be right or would I rather be kind? Practice saying I might be wrong or I see your point. Accepting that multiple perspectives can exist at once reduces conflict and helps you build deeper, more meaningful connections with others.");
        data.put("CBT-022", "【Heaven's Reward Fallacy】This is the expectation that your sacrifice and hard work will eventually pay off as if some global force is keeping score. When the reward doesn't come, you feel cheated and bitter. Identify this by the thought After all I've done, this shouldn't be happening. To apply a new outlook, try to find the reward in the action itself. If you help someone, do it because it aligns with your values, not for an expected return. This shift prevents resentment and allows you to live more authentically and peacefully in the present.");
        data.put("CBT-023", "【Blaming】Blaming is the opposite of personalization; it’s holding others responsible for your pain or problems. While others do have an impact, blaming them for how you feel takes away your agency. Identify this by the thought It’s their fault I'm unhappy. To apply a change, acknowledge the other person's role but focus on your response. By taking responsibility for your own emotional state, you stop being a passenger in your life and start being the driver. This doesn't mean excusing bad behavior, but it does mean owning your healing process.");
        data.put("CBT-024", "【Filtering the Future】This is a specific type of anxiety-driven distortion where you only see negative possibilities for what's ahead. You ignore your past successes and focus only on potential pitfalls. Identify this when planning feels like a list of reasons to be afraid. To apply a change, conduct a reality check. Look at times you've handled uncertainty before. Remind yourself of your resources and strengths. By balancing your view of the future with your actual track record of resilience, you can move forward with a sense of cautious optimism rather than paralyzing dread.");
        data.put("CBT-025", "【Rigid Standards】Rigid standards are internal rules that are so strict they are almost impossible to follow. You might believe you must always be the best or never show weakness. Identify this by a constant feeling of being under a microscope. To apply a fix, try to turn your rules into flexible guidelines. Instead of I must never fail, try I aim to do my best, but it's okay if I stumble. Being flexible with yourself allows for growth and learning, whereas rigidity only leads to breakage and burnout when life gets messy.");
        data.put("CBT-026", "【Double Standards】This happens when you are much harder on yourself than you would ever be on a friend. If a friend made a mistake, you'd be supportive, but for yourself, you're harsh. Identify this by noticing your internal tone of voice. To apply a correction, use the friend test. Ask yourself, what would I say to someone I love in this situation? Try to offer that same kindness to yourself. You deserve the same compassion you so easily give to others. Treating yourself as a friend changes your entire internal atmosphere for the better.");
        data.put("CBT-027", "【Discounting Evidence】This is when you ignore any facts that contradict your negative beliefs. If you believe you are unlikable, you might ignore the five people who texted you today and focus on the one who didn't. Identify this by the way you explain away positive data. To apply a fix, act like a scientist. Look at all the data points, even the ones that don't fit your current theory. By forcing yourself to acknowledge evidence that you are capable and loved, you slowly weaken the grip of your negative self-narratives.");
        data.put("CBT-028", "【Over-responsibility】This is the heavy feeling that you are responsible for the outcomes of everything around you, including things you can't possibly control. Identify this by the urge to fix every problem you see, even if it's not yours. To apply a fix, practice the art of letting go. Remind yourself that others are capable and have their own paths to walk. You can offer support without taking over the burden. Learning the difference between being helpful and being over-responsible saves your energy for the things that truly belong to you.");
        data.put("CBT-029", "【The Perfectionism Trap】Perfectionism isn't about being high-achieving; it's about the fear of being seen as flawed. It leads to procrastination because if you can't do it perfectly, why try? Identify this by a paralyzing fear of starting new things. To apply a change, embrace the idea of being a beginner. Tell yourself that done is better than perfect. Give yourself permission to make a messy first draft. Shifting your goal from perfection to progress releases the pressure and actually makes you more productive and creative in the long run.");
        data.put("CBT-030", "【Emotional Blackmail】This is an internal distortion where you use your own guilt or fear to force yourself into actions you don't want to do. You might think If I don't do this, I'm a horrible person. Identify this by the feeling of being bullied by your own thoughts. To apply a fix, check in with your values. Are you acting out of love or out of fear? Choosing to do things because they matter to you, rather than because you're afraid of your own judgment, leads to a much more authentic and less stressful life.");
        data.put("CBT-031", "【Static Labeling】This is when you view yourself or others as unchangeable. You might think I'm just an anxious person as if it's a permanent personality trait. Identify this by the use of the word just or simply. To apply a shift, use growth-oriented language. Instead of I am anxious, try I am experiencing anxiety right now. This small change reminds you that feelings and states are temporary. You are a dynamic person who is constantly evolving, and your current struggles don't have to be your permanent identity.");
        data.put("CBT-032", "【Minimizing Needs】You might tell yourself that your feelings or needs don't matter as much as others'. You might say I shouldn't be upset about this when others have it worse. Identify this by the dismissal of your own discomfort. To apply a change, recognize that suffering isn't a competition. Your feelings are valid simply because you are feeling them. Acknowledging your needs is the first step toward meeting them. When you stop minimizing yourself, you gain the clarity and strength needed to actually solve the problems you're facing.");
        data.put("CBT-033", "【The Need to Please】This distortion convinces you that your worth is based on making everyone else happy. If someone is upset, you feel you've failed. Identify this by the constant urge to apologize or check in on others' moods. To apply a fix, remember that you are not responsible for managing other people's emotions. It is okay to be liked by some and not by others. Focus on being true to yourself and your values. Authentic relationships are built on honesty, not on you performing a version of yourself that you think others want.");
        data.put("CBT-034", "【Assuming Intent】This is mind-reading with a negative twist—assuming people have bad intentions toward you. If a car cuts you off, you decide they did it to annoy you personally. Identify this by immediate feelings of anger or victimization. To apply a change, try the most generous interpretation. Maybe the driver is in a rush to a hospital. By giving people the benefit of the doubt, you reduce your own stress and avoid carrying around unnecessary anger toward strangers who likely didn't even notice you.");
        data.put("CBT-035", "【Comparing Your Insides to Outsides】You know all your own messy thoughts and doubts, but you only see the polished exterior of others. This leads to the distortion that everyone else has it together while you're struggling. Identify this by the thought Everyone else is so much more confident. To apply a fix, remind yourself that everyone has a hidden world of insecurity. Realizing that doubt is a universal human experience makes you feel less alone and more connected to others, rather than standing on the outside looking in.");
        data.put("CBT-036", "【Catastrophic Predicting】Similar to fortune telling, this is specifically about imagining a domino effect of disaster. One bad grade means failing the class, which means dropping out, which means no job. Identify this by the speed at which your thoughts travel from a small event to a life-ruining one. To apply a fix, interrupt the dominoes. Stop at the first event. What can you do about that one grade right now? Dealing with one small problem at a time prevents the imaginary mountain from ever forming in your mind.");
        data.put("CBT-037", "【Selective Memory】This is focusing only on past failures while forgetting all the times you succeeded. It builds a false narrative that you are incapable. Identify this when you say I've never done anything right. To apply a change, keep a success log. Write down small wins every day. When your brain tries to tell you that you always fail, look at your log as physical proof to the contrary. Retraining your memory to include your strengths builds a more balanced and resilient self-image that can withstand difficult days.");
        data.put("CBT-038", "【Black-and-White Relationships】This is seeing people as either all good or all bad. One mistake by a friend makes them a traitor. Identify this by rapid shifts in how you feel about people. To apply a fix, practice seeing the complexity in others. People are capable of being both kind and selfish, or helpful and annoying. Accepting that people are a mix of traits helps you build more stable, long-term relationships and prevents the cycle of getting very close and then pushing people away when they inevitably show a flaw.");
        data.put("CBT-039", "【The Ought-To Habit】This is a cousin to should statements, where you live by an invisible set of cultural or familial rules that don't actually fit you. Identify this by the phrase People my age ought to be... or I ought to want... To apply a fix, ask yourself who wrote these rules. If the rules don't serve your happiness or values, give yourself permission to ignore them. Living by your own authentic standards rather than borrowed ones is a huge step toward mental well-being and personal fulfillment.");
        data.put("CBT-040", "【Hyper-Responsibility for Others】You feel like if you don't warn everyone of every danger, or solve their problems, something terrible will happen. Identify this by a high level of vigilance and anxiety about other people's choices. To apply a change, practice trust. Trust that others can learn from their own mistakes and handle their own challenges. This doesn't mean you stop caring, but it does mean you stop carrying. Releasing this burden allows you to be a more supportive, less anxious presence in the lives of those you love.");
        data.put("CBT-041", "【Evidence Testing】When a negative thought feels like an absolute truth, try putting it on trial. Identify the thought, like I'm bad at my job, and look for actual evidence. What facts support this? What facts contradict it? Usually, we find our thoughts are based more on feelings than facts. By looking at the objective data—like positive feedback or finished tasks—you can shrink the negative thought down to size. This technique helps you stay grounded in reality and prevents your emotions from rewriting your life story into something darker than it actually is.");
        data.put("CBT-042", "【Alternative Explanations】Our first guess about why something happened isn't always the right one. If a friend doesn't text back, your brain might jump to They're mad at me. Identify this as one possibility, then brainstorm three others. Maybe they're busy, their phone died, or they just forgot. To apply this, try to find the most mundane explanation. Shifting your focus to these alternatives lowers your anxiety and stops you from taking everything personally. It’s a great way to give your mind some breathing room and prevent unnecessary social stress.");
        data.put("CBT-043", "【Cognitive Restructuring】Think of this as an upgrade for your brain's software. It involves identifying a distorted thought, challenging it, and then replacing it with something more balanced. For example, change I'll never be happy again to This is a really hard day, but I've felt better before and I will again. To apply this, don't just stop the negative thought—actively build a new one. It isn't about being fake-positive; it's about being accurate. A balanced thought acknowledges the struggle while also leaving space for hope and reality-based resilience.");
        data.put("CBT-044", "【Behavioral Experiments】Sometimes you have to see it to believe it. If you're afraid of being judged, test that theory with a small experiment. Try wearing your shirt inside out or making a small mistake in public and see if people actually react. Most of the time, the evidence shows that people are way too busy with themselves to notice us. Identify your fear, predict what will happen, and then gather real-world data. These experiments are powerful because they provide lived proof that your fears are often much scarier in your head than in real life.");
        data.put("CBT-045", "【Double Standard Technique】We are often our own worst critics. To identify a double standard, ask yourself: would I say what I'm thinking about myself to a friend? If you'd never tell a friend they are a hopeless failure, then why say it to yourself? To apply this, try talking to yourself with the same kindness and logic you'd offer a loved one. This technique helps you step outside your own bias and realize that you deserve the same grace, patience, and support that you so freely give to others every day.");
        data.put("CBT-046", "【Downward Arrow Technique】This technique helps you find the core belief hiding under a surface-level worry. Start with a thought like I might mess up this speech. Then ask, And if I do, what would that mean? Follow the arrows down through each answer until you reach the root, like I'm fundamentally incompetent. To apply this, once you find that core belief, you can challenge it directly. Knowing the root of your anxiety makes it much easier to dismantle than just fighting the surface-level worries that keep popping up like weeds.");
        data.put("CBT-047", "【Thought Records】A thought record is a structured way to process a difficult moment. You write down the situation, the emotion you felt, and the negative thought that popped up. Then, you list evidence for and against that thought. Finally, you write a new, balanced perspective. Using a thought record helps you slow down and look at your problems with a logical eye. It is like being your own therapist. Over time, this practice trains your brain to automatically look for evidence and balance, making you much more resilient to sudden spikes of stress.");
        data.put("CBT-048", "【The Responsibility Pie】If you feel 100% responsible for a bad outcome, try drawing a pie chart. Give yourself a slice, but also give slices to other people involved, the situation, and just plain bad luck. For example, if a party was awkward, maybe 10% was your shyness, but 40% was the loud music and 50% was the fact that most people didn't know each other. This isn't about dodging blame; it's about accurate accounting. Seeing that you are only one part of a complex situation helps lift the heavy weight of unnecessary guilt.");
        data.put("CBT-049", "【Worst-Case, Best-Case, Likely-Case】When you're worried about the future, your brain often gets stuck on the worst-case scenario. To break out, intentionally imagine the best-case scenario too. Once you've looked at both extremes, find the middle ground—the most likely case. Usually, the likely case is manageable and far less scary than the disaster you were imagining. This technique helps you prepare for reality rather than reacting to a nightmare. It moves you from a state of panic into a state of practical planning, which is much more effective and peaceful.");
        data.put("CBT-050", "【Externalizing the Problem】Sometimes it helps to treat your negative thoughts as an external character rather than your own voice. Give your inner critic a silly name or imagine it as a grumpy old man in a movie. When a thought like You're not good enough pops up, you can say, Oh, that's just Grumpy Dave again. This creates distance between you and the thought. You realize that you don't have to believe everything you think. It makes the struggle feel less personal and more like something you can manage with a bit of humor.");
        data.put("CBT-051", "【Defining Your Terms】If you're calling yourself a loser or a failure, stop and ask: what is the actual definition of a loser? Usually, we find our definitions are so broad or so harsh that no human could actually avoid them. To apply this, realize that labeling yourself is inaccurate. You are a person who does things—some go well, some don't. By breaking down vague, scary labels into specific actions, you make them much easier to fix. You can't fix being a loser, but you can fix being late for a meeting.");
        data.put("CBT-052", "【The Survey Method】If you're convinced that everyone would judge you for something, try asking around. You can ask a few trusted friends how they would feel in your situation. Often, you'll find that they are much more forgiving and understanding than you imagined. This provides external evidence to counter your internal bias. Hearing others say I've felt that way too or It’s not a big deal can be incredibly healing. It breaks the isolation of your negative thoughts and reminds you that you are part of a kind, imperfect human community.");
        data.put("CBT-053", "【Cost-Benefit Analysis】If you're stuck in a habit like worrying or procrastinating, ask yourself: what is this costing me, and what am I getting out of it? Maybe worrying makes you feel prepared, but the cost is constant stress and lack of sleep. To apply this, write it down. When you see that the costs far outweigh the benefits, it becomes much easier to motivate yourself to change. It moves the conversation from I shouldn't do this to I don't want to do this because it's hurting me, which is a much more powerful stance.");
        data.put("CBT-054", "【Shifting the Focus】When you're caught in a loop of negative thinking, try to intentionally move your attention to something else. This isn't ignoring your problems, it's giving your brain a break. Focus on a task that requires concentration, like a hobby or a work project. To apply this, notice when you're ruminating and say, I'll think about this later, but right now I'm doing X. This shows you that you have control over your attention. By breaking the cycle, you often return to the problem later with a much clearer and more capable mindset.");
        data.put("CBT-055", "【Checking the Validity】Not every thought that pops into your head is true or even useful. When a negative thought hits, ask: is this thought helping me solve a problem, or is it just making me feel bad? If it's not useful, you have permission to let it go. To apply this, treat your thoughts like junk mail. You don't have to open every envelope and act on its contents. By sorting your thoughts based on their helpfulness, you save your mental energy for the things that actually lead to positive change and emotional well-being.");
        data.put("CBT-056", "【Historical Review】If you feel like you're always failing, take a look back at your whole life. Look for times you were successful, brave, or kind. Often, we focus so much on recent mistakes that we forget our long history of being capable. To apply this, write a list of your wins, big and small. This historical data provides a powerful counter-argument to the distortion that you are inherently flawed. Reminding yourself of who you've been at your best helps you have more confidence in who you can be right now.");
        data.put("CBT-057", "【Acting As If】Sometimes the best way to change a thought is to change your behavior first. If you think you're unconfident, ask yourself: how would a confident person act in this situation? Then, try to act that way for just ten minutes. To apply this, notice how it feels and what the actual results are. Often, you'll find that acting differently leads to different reactions from others and, eventually, a different view of yourself. This fake it till you make it approach is a practical way to gather evidence that you are more capable than you think.");
        data.put("CBT-058", "【Identifying Triggers】Negative thoughts don't usually appear out of nowhere. They are often triggered by specific situations, people, or even physical states like hunger or tiredness. To apply this, start noticing the patterns. Do you feel worse on Sunday nights? After talking to a certain person? Once you know your triggers, you can prepare for them. You might plan a relaxing activity for Sunday or practice your CBT techniques before a difficult meeting. Being proactive makes you feel much less like a victim of your moods and more like a manager of your life.");
        data.put("CBT-059", "【The Shades of Gray】Black-and-white thinking is a major source of distress. To challenge it, try to place your situation on a scale of 0 to 100. If you feel like a failure, ask: am I a 0% success? Usually, you'll find you're somewhere in the middle, like a 40% or 60%. To apply this, look for the partial successes and the things that went okay. Acknowledging the middle ground reduces the intensity of your emotions. It’s a more accurate way to view the world and yourself, allowing for growth without the crushing weight of perfectionism.");
        data.put("CBT-060", "【Questioning the Source】We often carry around negative beliefs that aren't even ours—they might come from a critical parent, a past bully, or societal pressure. When a harsh thought pops up, ask: whose voice is this? Identifying that a thought isn't your own true voice can make it much easier to dismiss. To apply this, try to replace that old, borrowed voice with your own compassionate one. You have the right to decide which beliefs you want to keep and which ones you want to return to sender. It’s your mind, after all.");
        data.put("CBT-061", "【Re-evaluating Expectations】Sometimes our negative thoughts come from unrealistic expectations we’ve set for ourselves. If you expect to be happy 100% of the time, you'll feel like a failure whenever you're sad. To apply this, check if your expectations are humanly possible. Are you expecting yourself to be a robot? Shifting your expectations to be more realistic—like aiming for resilience rather than constant happiness—makes you feel much more successful. It allows you to accept the natural ups and downs of life without feeling like every down is a sign that something is fundamentally wrong.");
        data.put("CBT-062", "【The What-If Flip】Anxiety is great at asking What if things go wrong? To challenge this, try to flip it: What if things go right? Or even, What if I can handle it even if it does go wrong? To apply this, intentionally spend as much time imagining a positive or manageable outcome as you do imagining a disaster. This simple shift breaks the monopoly that fear has on your imagination. It reminds you that there are many possible futures, and many of them are ones where you are okay, capable, and even happy.");
        data.put("CBT-063", "【Perspective Taking】When you're stuck in a problem, try looking at it from someone else's point of view. What would your hero say about this? What would you think of this situation if it were happening to someone else? Shifting your perspective helps you see things more objectively. To apply this, literally imagine yourself standing in another part of the room or looking down from a high place. This mental distance can shrink a problem and reveal solutions you couldn't see when you were right in the middle of it. It’s a great way to find some clarity.");
        data.put("CBT-064", "【Language Audit】The words we use in our heads have a huge impact on how we feel. Do you use words like disaster, nightmare, or hate for minor problems? To apply a fix, try using more neutral language. Instead of This is a disaster, try This is an inconvenience. Instead of I hate this, try I find this challenging. Changing the intensity of your language can actually lower the intensity of your emotional response. It’s a simple but powerful way to keep your cool and stay in control when things get stressful.");
        data.put("CBT-065", "【The Time Machine】Imagine you are looking back at your current problem from ten years in the future. How much will it matter then? Most of the things we worry about today won't even be a memory in a decade. To apply this, use that future perspective to lower your current stress. It helps you distinguish between true life-altering events and temporary setbacks. This long-term view brings a sense of proportion to your daily struggles, helping you stay calm and focused on what truly matters in the grand scheme of your life.");
        data.put("CBT-066", "【Examining the Function】Sometimes we hold onto negative thoughts because we think they serve a purpose, like keeping us humble or preventing us from being disappointed. To apply this, look closely at that belief. Is the negativity actually protecting you, or is it just holding you back? Usually, you can find better ways to stay humble or prepared that don't involve making yourself miserable. Replacing a harmful defense mechanism with a healthy one—like being cautious but hopeful—gives you the protection you want without the high cost of constant self-criticism.");
        data.put("CBT-067", "【Mindful Observation】Instead of fighting a negative thought, try just watching it. Imagine your thoughts are clouds passing in the sky or cars driving past your house. You are the observer, not the thought itself. To apply this, say to yourself, I am having the thought that I'm not good enough. This small addition—I am having the thought—reminds you that the thought is just a mental event, not an absolute truth. It gives you the space to let the thought go without getting tangled up in it or letting it dictate your mood.");
        data.put("CBT-068", "【Searching for Nuance】Negative thoughts love to be simple and extreme. Real life is usually complex and nuanced. When you have an extreme thought, look for the details you're missing. What part of this is true, and what part is an exaggeration? To apply this, try to describe your situation in a paragraph rather than a single sentence. Adding more detail and nuance naturally breaks down extreme distortions. It’s like turning up the lights in a dark room—the scary shadows turn back into ordinary objects that you can easily handle.");
        data.put("CBT-069", "【The Acceptance Shift】Sometimes we make things worse by fighting the fact that we're struggling. This is called secondary distress—feeling bad about feeling bad. To apply a fix, try accepting the initial feeling: I am feeling anxious right now, and that's okay. It makes sense because I have a big day. Acceptance isn't about liking the feeling; it's about stopping the internal war against it. When you stop fighting the feeling, its intensity often drops on its own, leaving you with more energy to actually deal with the situation at hand.");
        data.put("CBT-070", "【Goal-Oriented Thinking】When you're stuck in a negative loop, ask yourself: is this thinking helping me move toward my goals? If your goal is to have a good evening with your family, but you're obsessing over a work email, that thought is taking you away from what matters. To apply this, use your goals as a compass. Intentionally choose thoughts and actions that align with the kind of person you want to be. This shifts you from being reactive to being intentional, which is a key part of long-term mental health and personal satisfaction.");
        data.put("CBT-071", "【Piecing Together the Whole】We often judge ourselves by our worst moments, but that’s like judging a whole movie by one bad scene. To apply a more balanced view, try to look at your whole life as a collection of scenes. There are scenes of failure, sure, but also scenes of laughter, perseverance, and kindness. Remind yourself that the bad moments don't cancel out the good ones. By seeing yourself as a whole person with a full range of experiences, you become much more resilient and less likely to be crushed by a single difficult day or mistake.");
        data.put("CBT-072", "【The Scientist's Mindset】Try to look at your thoughts and life with a sense of curiosity rather than judgment. If you fail at something, instead of saying I'm a failure, say That's interesting, I wonder why that happened? What can I learn for next time? To apply this, treat every experience as a data point. This curiosity removes the sting of failure and turns it into a useful lesson. It keeps you in a growth mindset, where you are always learning and evolving, rather than a fixed mindset where you are always being judged and found wanting.");
        data.put("CBT-073", "【The Compassion Bridge】If you find it hard to be kind to yourself, imagine someone you love is going through exactly what you are. What would you say to them? Now, imagine saying those same words to yourself. To apply this, actually write down the supportive words and read them out loud. This bridges the gap between the kindness you give others and the harshness you give yourself. It helps you realize that you are just as deserving of support and understanding as anyone else in your life, which is a fundamental truth of mental well-being.");
        data.put("CBT-074", "【Breaking the Loop】Rumination is when your brain gets stuck on a negative thought like a broken record. To break the loop, you need a physical or mental circuit breaker. Try a quick burst of exercise, a cold splash of water, or a challenging mental puzzle. To apply this, have your circuit breakers ready before you need them. When you notice the loop starting, immediately switch to your chosen activity. This doesn't solve the problem, but it stops the emotional spiral, giving you the chance to approach the issue later with a much calmer and more effective mindset.");
        data.put("CBT-075", "【Values over Validation】We often feel bad because we are seeking validation from others. To challenge this, focus on your own values instead. Ask: did I act in a way that aligns with my values? If you value kindness and you were kind, then you've succeeded, regardless of how the other person reacted. To apply this, make a list of your core values. When you feel judged, check your actions against your own list. Living for your own approval rather than others' is the most stable and satisfying way to build self-esteem and a sense of inner peace.");
        data.put("CBT-076", "【Identifying the Narrative】We all have an internal story about who we are. Some people have a story that says I'm the one things always go wrong for. To apply a change, start noticing when you are following an old, negative script. Ask: is this story still true? Is it useful? You have the power to edit your narrative. Start looking for evidence that supports a new story, like I am someone who can handle challenges. By intentionally changing the story you tell yourself, you change how you experience your life and what you believe is possible.");
        data.put("CBT-077", "【Focusing on Effort】We can't always control outcomes, but we can control our effort. If you focus only on the result, you'll feel like a failure whenever things don't go perfectly. To apply a shift, practice praising yourself for the work you put in. Say, I'm proud that I tried, or I did a good job sticking with that task even though it was hard. This builds a sense of mastery that isn't dependent on external success. It keeps you motivated and resilient, as your sense of self-worth is rooted in your own actions rather than luck or timing.");
        data.put("CBT-078", "【The Balance Beam】Try to find a balanced thought that acknowledges both the difficulty and your ability to cope. Instead of I can't handle this, try This is really hard, and I'm struggling, but I've handled hard things before and I'll find a way through this one too. To apply this, look for the and in your thoughts. You can be both scared and brave, or sad and capable. This balanced approach is much more grounded in reality and provides a much stronger foundation for emotional stability than either extreme negativity or forced, unrealistic positivity.");
        data.put("CBT-079", "【The Responsibility Reset】If you feel overwhelmed by everyone else's problems, it's time for a responsibility reset. Ask: is this my problem to solve? Is it helping the other person if I take over? To apply this, practice letting others handle their own consequences. It shows you trust them to be capable. Reclaiming your own boundaries reduces your stress and allows you to be a more supportive, less drained friend or family member. Remember, you can be a compassionate witness to someone's struggle without having to be the one who fixes it for them.");
        data.put("CBT-080", "【Celebrating Small Steps】When you're overwhelmed, it's easy to feel like you're not doing enough. To counter this, start noticing and celebrating every tiny thing you do right. Did you get out of bed? Great. Did you send one email? Awesome. To apply this, keep a Ta-Da list instead of just a To-Do list. Write down everything you've accomplished at the end of the day. This builds momentum and shifts your focus from what's missing to what's present. Over time, these small celebrations build a much more positive and capable self-image that can take on bigger challenges.");
        data.put("CBT-081", "【Mindful Breathing】Mindful breathing is a simple way to anchor yourself in the present moment. It involves focusing your attention on the physical sensation of your breath as it enters and leaves your body. You can identify the need for this when you feel scattered, overwhelmed, or stuck in your thoughts. To apply it, just take a few slow, deep breaths. Notice the rise and fall of your chest. When your mind wanders—and it will—gently bring it back to your breath without judgment. This practice calms your nervous system and gives you a quiet space to reset, no matter what is happening around you.");
        data.put("CBT-082", "【Body Scan】A body scan is a technique where you mentally travel through your body, noticing any sensations of tension, warmth, or discomfort. It’s a great way to reconnect with yourself when you’ve been living in your head too much. To apply this, start at your toes and slowly move up to the top of your head. Just notice what you feel without trying to change anything. If you find tension, you might imagine breathing into that area to help it soften. This practice helps you catch stress early before it turns into physical pain or a full-blown emotional spiral.");
        data.put("CBT-083", "【Progressive Muscle Relaxation】This technique involves intentionally tensing and then releasing different muscle groups in your body. It helps you learn the difference between the feeling of tension and the feeling of relaxation. To apply this, start with your feet: squeeze them tight for five seconds, then let go completely and feel the tension drain away. Move up to your calves, thighs, and so on. This physical reset is especially helpful for people who carry stress in their bodies. It’s a practical way to physically signal to your brain that it is safe to relax and let go of the day's pressure.");
        data.put("CBT-084", "【Emotion Surfing】Emotion surfing is the practice of noticing a strong emotion and riding it like a wave, rather than trying to push it away or being swept away by it. Every emotion, no matter how intense, has a beginning, a peak, and an end. To apply this, when a feeling like anger or sadness hits, try to observe it with curiosity. Where do you feel it in your body? How intense is it? Remind yourself that the feeling will eventually subside on its own. By surfing the emotion, you learn that you can handle even the biggest waves without losing your balance.");
        data.put("CBT-085", "【Emotion Naming】Naming your emotion—often called name it to tame it—can significantly reduce its power over you. When you’re feeling overwhelmed, try to put a specific word to it: is it frustration, loneliness, or maybe just tiredness? To apply this, say to yourself, I am feeling X right now. This simple act shifts the activity in your brain from the emotional center to the logical center. It gives you a sense of distance and control, making the emotion feel like something you are experiencing rather than something that defines you or your entire day.");
        data.put("CBT-086", "【Grounding Techniques】Grounding techniques are tools that help pull you out of an emotional spiral and back into the here and now. They are especially useful for moments of high anxiety or panic. To apply a simple grounding method, touch something nearby and focus on its texture, temperature, and weight. Is it smooth, cold, or heavy? By engaging your senses in the physical world, you send a clear message to your brain that you are safe in the present moment. This breaks the cycle of frightening thoughts and helps your body return to a state of calm and clarity.");
        data.put("CBT-087", "【5-4-3-2-1 Technique】The 5-4-3-2-1 technique is a popular grounding exercise that uses all five of your senses to bring you back to the present. To apply it, look around and name five things you can see, four things you can touch, three things you can hear, two things you can smell, and one thing you can taste. This forced shift in attention interrupts the internal noise of anxiety. It’s like a mental reset button that reminds you of your actual surroundings, helping you feel more centered and less overwhelmed by whatever is happening in your mind.");
        data.put("CBT-088", "【TIPP Skills - Temperature】TIPP is a set of skills for rapid emotional regulation, and the T stands for Temperature. When you're in an extreme emotional state, changing your body temperature can act as a circuit breaker for your nervous system. To apply this, try splashing cold water on your face or holding an ice cube in your hand. The cold triggers the mammalian dive reflex, which naturally slows your heart rate and calms your body down. It’s a powerful, physical way to de-escalate intense feelings like rage or panic when logic and talking just aren't working yet.");
        data.put("CBT-089", "【TIPP Skills - Intense Exercise】The I in TIPP stands for Intense Exercise. When you're full of pent-up emotional energy, a short burst of physical activity can help burn it off and reset your mood. To apply this, try doing jumping jacks, running in place, or even just dancing vigorously for one or two minutes. This physical exertion releases endorphins and uses up the stress hormones that make you feel keyed up. It’s a healthy way to channel intense emotions into physical movement, leaving you feeling more relaxed and capable of thinking clearly again afterward.");
        data.put("CBT-090", "【TIPP Skills - Paced Breathing】The first P in TIPP stands for Paced Breathing. This involves slowing down your breath to a specific rhythm to calm your nervous system. To apply this, try breathing in for four counts and out for six counts. The key is making the exhale longer than the inhale, which signals your body to move from fight-or-flight mode into rest-and-digest mode. Practicing this for just a few minutes can lower your heart rate and reduce feelings of anxiety, making it a great tool to use anytime you feel your stress levels starting to rise.");
        data.put("CBT-091", "【TIPP Skills - Paired Muscle Relaxation】The second P in TIPP stands for Paired Muscle Relaxation. This is similar to progressive relaxation but focuses on pairing the release of tension with a calming word. To apply this, tense a muscle group as you breathe in, and as you breathe out, release the tension while mentally saying a word like calm or relax. Over time, your brain starts to associate the word with the physical feeling of relaxation. This makes it easier to trigger a sense of peace just by using your cue word when you're in a stressful situation.");
        data.put("CBT-092", "【Safe Space Visualization】Visualization involves using your imagination to create a mental sanctuary where you feel completely safe and at peace. You can use this whenever you need to escape from a stressful environment or internal turmoil. To apply it, close your eyes and imagine a place where you feel perfectly relaxed. It could be a real place from your past or an imaginary beach or forest. Focus on the details: the sounds, the smells, and the feeling of the air. Spending even a few minutes in your safe space can significantly lower your stress and recharge your emotional battery.");
        data.put("CBT-093", "【The Worry Jar】A worry jar is a mental or physical place where you store your worries so you don't have to carry them all day. To apply this, when a worry pops up, write it down and put it in a jar, or imagine placing it in a secure box in your mind. Tell yourself, I have captured this worry, and I will check on it later. This gives you permission to stop thinking about it for now. It helps you stay focused on your day without the constant distraction of nagging thoughts, knowing they are safe and waiting for a better time to be addressed.");
        data.put("CBT-094", "【Self-Soothing with Senses】Self-soothing involves using pleasant sensory experiences to comfort yourself during times of distress. To apply this, think about what calms each of your senses. Maybe it’s a soft blanket for touch, a favorite song for hearing, a scented candle for smell, or a warm cup of tea for taste. Having a self-soothing kit ready—either physically or as a mental list—allows you to quickly provide yourself with comfort when things get hard. It’s a way of being your own caregiver and treating yourself with the kindness and care you need to feel okay again.");
        data.put("CBT-095", "【HALT Technique】HALT stands for Hungry, Angry, Lonely, and Tired. These four physical and emotional states can make it much harder to regulate your emotions. To apply this, whenever you feel an emotional spike, stop and ask: Am I any of these four things? Often, what feels like a major life crisis is actually exacerbated by being tired or hungry. Addressing these basic needs first—like having a snack or a nap—can bring your emotions back down to a manageable level, allowing you to see the situation more clearly and react more effectively.");
        data.put("CBT-096", "【Opposite Action】Opposite action is a technique where you intentionally do the opposite of what your emotion is telling you to do. For example, if you feel like isolating because you’re sad, the opposite action would be to reach out to a friend. If you’re angry and want to shout, the opposite action is to speak softly and calmly. To apply this, first identify the action urge of your emotion. If that urge isn't helpful, try the opposite. This doesn't suppress the emotion, but it prevents the emotion from dictating your behavior in ways that might make things worse.");
        data.put("CBT-097", "【Radical Acceptance】Radical acceptance is about fully accepting reality as it is, without judgment or trying to fight it. This doesn't mean you like what's happening or that you won't try to change things in the future, but it means you stop wasting energy on saying This shouldn't be happening. To apply this, notice when you're resisting reality and try saying, It is what it is. Accepting the present moment reduces the suffering caused by your internal struggle, giving you a clearer mind and more energy to actually figure out your next steps toward a better future.");
        data.put("CBT-098", "【Mindful Walking】Mindful walking is a way to practice awareness while moving. Instead of walking to get somewhere, walk to notice the sensation of walking. To apply this, focus on the feeling of your feet hitting the ground, the movement of your legs, and the rhythm of your breath. Notice the sights and sounds around you without judging them. This practice turns an everyday activity into a moving meditation. It’s a great way to clear your head and ground yourself when you’re feeling restless or stuck, helping you feel more connected to your body and the world around you.");
        data.put("CBT-099", "【Distraction with Activities】Sometimes the best way to handle a difficult emotion is to temporarily move your focus to something else. This isn't about avoiding your feelings forever, but about giving yourself a break when things are too intense. To apply this, choose an activity that requires your full attention, like a complex hobby, a game, or a detailed task. By engaging your mind in something else, you allow the peak of the emotion to pass. This leaves you in a much better place to process the feeling later, when it’s not so overwhelming and you have more mental space.");
        data.put("CBT-100", "【The 3-3-3 Rule】The 3-3-3 rule is a quick grounding exercise to use when you feel overwhelmed by anxiety. To apply it, look around and name three things you see, then three sounds you hear, and finally, move three parts of your body, like your fingers, your toes, and your neck. This simple sequence pulls your brain out of its internal worry loop and forces it to interact with the physical world. It’s a fast, discreet way to center yourself in the middle of a meeting, a crowd, or any situation where you start to feel a spike of panic.");
        data.put("CBT-101", "【Box Breathing】Box breathing is a technique used by athletes and high-performers to stay calm under pressure. Imagine a square: breathe in for four counts, hold for four, out for four, and hold empty for four. To apply this, repeat the cycle four times. This rhythmic breathing regulates your heart rate and signals to your brain that you are in control. It is an excellent tool for those moments right before a big event or when you feel a wave of stress hitting you. It’s a portable, invisible way to bring yourself back to a state of focused calm.");
        data.put("CBT-102", "【Externalizing the Emotion】Instead of saying I am sad, try saying I am feeling sadness. This creates a small but powerful distance between you and the emotion. To apply this further, imagine the emotion as a guest in your house. It has arrived, it’s staying for a bit, but it’s not the owner of the house. You can even imagine what it looks like or what color it is. This externalization helps you remember that you are the container for the emotion, not the emotion itself. It makes the feeling seem more manageable and less like a permanent part of who you are.");
        data.put("CBT-103", "【The ABC of Emotions】ABC stands for Activating event, Belief, and Consequence. An event happens (A), we have a belief about it (B), and that leads to our emotional consequence (C). To apply this, when you're upset, look at the B. What are you telling yourself about what happened? Often, it’s our interpretation, not the event itself, that causes the most pain. By changing your belief—for example, shifting from He's ignoring me to He's just busy—you can change the emotional consequence. This technique puts the power over your feelings back into your own hands through logical reflection.");
        data.put("CBT-104", "【Leaves on a Stream】This is a classic visualization for letting go of nagging thoughts. Imagine you are sitting by a gently flowing stream with leaves floating on the surface. To apply this, every time a thought pops into your head, place it on a leaf and watch it float away. If the same thought comes back, just put it on another leaf. Don't try to stop the thoughts or speed them up; just watch them pass. This practice teaches you that thoughts are temporary and that you can observe them without having to get pulled into the water with them.");
        data.put("CBT-105", "【Checking the Intensity】Sometimes we react to a small problem with 10/10 intensity. To apply this technique, when you're upset, ask yourself: On a scale of 1 to 10, how big is this problem really? Then ask: How big is my reaction right now? If there’s a mismatch, try to intentionally bring your reaction level down to match the problem's size. This doesn't mean your feelings don't matter, but it helps you save your 10/10 energy for the things that truly need it. It keeps your emotional responses proportionate, which leads to much more stable and manageable days.");
        data.put("CBT-106", "【The Power of Noticing】The first step in regulation is simply noticing what is happening without trying to fix it immediately. Notice the tightness in your chest or the speed of your thoughts. To apply this, try to be like an impartial reporter. Oh, my heart is racing right now, and I'm thinking about that deadline. This mindful noticing prevents you from reacting automatically to your discomfort. It creates a gap between the feeling and your action, and in that gap, you have the freedom to choose a response that actually helps rather than just reacting out of habit or fear.");
        data.put("CBT-107", "【Self-Validation】Validation means acknowledging that your feelings make sense given your situation and history. To apply this, try saying to yourself, It’s okay that I’m feeling this way. Anyone would be stressed in this position. This isn't about agreeing with your negative thoughts, but about being kind to the person feeling them—you. Self-validation stops the cycle of feeling guilty for your emotions, which often makes the original feeling even worse. By giving yourself permission to feel, you actually make it easier for the emotion to pass through you naturally and quickly.");
        data.put("CBT-108", "【The Anchor Point】An anchor point is a physical sensation you can return to anytime you feel lost in an emotional storm. It could be the feeling of your feet on the floor, the sensation of your hands touching each other, or your breath. To apply this, choose your anchor and practice returning to it several times a day when you’re already calm. Then, when a storm hits, your anchor will be ready. Focusing on that one stable sensation provides a sense of safety and stability that can help you stay upright until the worst of the emotional weather passes by.");
        data.put("CBT-109", "【Slowing Down the Clock】When we are overwhelmed, everything feels like it’s moving too fast, which adds to our panic. To apply this technique, intentionally slow down your physical movements. Walk more slowly, speak more slowly, and take an extra second before you respond to someone. This physical deceleration tells your brain that there is no immediate emergency. It breaks the sense of urgency that anxiety creates, allowing your logical mind to catch up with your emotions. By slowing down on the outside, you help create a sense of calm and control on the inside.");
        data.put("CBT-110", "【The Observer Self】Imagine there is a part of you that is always calm and just observes everything that happens. This is your observer self. To apply this, when you’re in a difficult situation, try to step back into that calm part of you. Watch yourself having the experience. This doesn't mean you stop feeling, but you realize that there is a part of you that is bigger than any single feeling or problem. This perspective provides a deep sense of resilience and stability, reminding you that you have an inner core that remains untouched by the daily ups and downs of life.");
        data.put("CBT-111", "【Primary vs. Secondary Emotions】A primary emotion is your first reaction, like feeling hurt when someone is mean. A secondary emotion is how you feel about that feeling, like being angry at yourself for being hurt. To apply this, focus on the primary emotion. It’s usually much simpler and easier to handle than the layer of judgment we add on top. By acknowledging the first feeling and letting go of the second, you simplify your emotional landscape. This prevents a single hurt from turning into a complex, days-long emotional drama, keeping your mental energy focused on healing rather than judging.");
        data.put("CBT-112", "【The Emotion Thermometer】Imagine your emotions on a thermometer from 1 to 100. At 20, you’re just starting to feel something; at 90, you’re in a crisis. To apply this, start checking your temperature throughout the day. If you notice you’re at a 40, use a regulation skill now to prevent it from reaching an 80. It is much easier to cool down a 40 than it is a 90. This proactive approach helps you stay in a manageable range and teaches you that you have the power to influence your emotional state before it becomes overwhelming or out of control.");
        data.put("CBT-113", "【Wise Mind】CBT often talks about the Emotional Mind (feelings) and the Rational Mind (logic). Your Wise Mind is the balance where the two meet. To apply this, when you have a decision to make, ask: What does my rational mind say? What does my emotional mind say? And then, what does my Wise Mind say? Wise Mind acknowledges your feelings but doesn't let them drive the car, and it uses logic without being cold. Acting from your Wise Mind leads to choices that you feel good about both in the moment and in the long run.");
        data.put("CBT-114", "【The Calm Breath】The way we breathe sends a direct signal to our brain about how safe we are. Chest breathing is for emergencies; belly breathing is for safety. To apply this, place one hand on your chest and one on your belly. Try to breathe so that only the hand on your belly moves. This deep, diaphragmatic breathing activates the vagus nerve, which is like a natural tranquilizer for your body. Making this your default way of breathing, especially during stress, can fundamentally change how your body handles pressure and help you maintain a sense of steady, quiet strength.");
        data.put("CBT-115", "【Positive Assets Search】When we feel down, we tend to only see our problems. To regulate your mood, intentionally look for your positive assets—things you have going for you, skills you possess, or people who care. To apply this, make a list of five assets whenever you feel a dip in your mood. This isn't about ignoring the problem, but about reminding yourself of the tools you have to solve it. Seeing your resources clearly builds confidence and reduces the feeling of being helpless, which is often the heaviest part of any difficult emotion or situation you're facing.");
        data.put("CBT-116", "【The Window of Tolerance】The window of tolerance is the emotional zone where you can handle life’s ups and downs effectively. Below the window, you’re numb; above it, you’re overwhelmed. To apply this, learn to recognize when you’re drifting toward the edges of your window. If you’re getting too keyed up, use a calming skill like deep breathing. If you’re getting too numb, use a stimulating skill like cold water or movement. Staying within your window allows you to live fully and respond to challenges with your best self, rather than just reacting out of survival mode.");
        data.put("CBT-117", "【Self-Compassionate Touch】Physical touch can release oxytocin, a hormone that lowers stress and increases feelings of safety. To apply this, when you’re feeling upset or lonely, try placing a hand on your heart, hugging yourself, or gently stroking your arm. It might feel silly at first, but your body responds to the warmth and pressure even if your mind is skeptical. This simple act of self-kindness provides immediate physical comfort and reminds you that you are here for yourself. It’s a powerful way to soothe your nervous system and provide a moment of peace in a difficult day.");
        data.put("CBT-118", "【The Acceptance Paradox】The paradox is that once you accept a feeling, it often starts to change. Resisting an emotion is like trying to hold a beach ball underwater—it takes constant effort and eventually pops up even harder. To apply this, try to say yes to your feelings. Yes, I am feeling jealous right now. This simple acknowledgment takes away the friction of resistance. When you stop fighting, the beach ball just floats on the surface and eventually drifts away. Acceptance is the fastest way to emotional change, even though it feels like the opposite of what you should do.");
        data.put("CBT-119", "【The Big Picture Shift】When an emotion feels like it’s everything, try to zoom out. Imagine your life as a large tapestry, and this current feeling as just one small thread. To apply this, ask yourself: In the whole story of my life, how much space does this one day or this one feeling take up? Zooming out helps you realize that while the feeling is real and valid, it is not your whole life. This perspective creates the space you need to breathe and reminds you that there are many other threads in your tapestry that are bright, strong, and beautiful.");
        data.put("CBT-120", "【Release Rituals】A release ritual is a physical action that symbolizes letting go of an emotion or a day’s stress. To apply this, you might try washing your hands at the end of a workday to wash off the stress, or writing a worry on a piece of paper and then shredding it. The physical act helps your brain move from one state to another. It creates a clear boundary between the time you were struggling and the time you are resting. These small rituals can be incredibly effective at helping you leave your worries behind and move into a more peaceful, present state.");
        data.put("CBT-121", "【Activity Scheduling】Behavioral activation is based on the idea that our mood follows our actions. When we feel down, we stop doing things, which makes us feel worse. To break this cycle, try activity scheduling. To apply this, plan just two or three simple activities for your day, like taking a walk or calling a friend. Write them down in a calendar. By committing to the action regardless of how you feel, you create opportunities for your mood to improve. Action is the spark that can eventually relight the fire of your motivation and joy, one small task at a time.");
        data.put("CBT-122", "【Pleasure Prediction】When you're depressed or anxious, you often predict that activities won't be fun or worth the effort. This is called a prediction error. To apply this technique, before you do an activity, rate how much pleasure you think you'll get from it (0-10). After you do it, rate how much you actually enjoyed it. Most people find they enjoy things more than they expected. Seeing this gap in writing helps challenge the negative voice that tells you everything is pointless. It encourages you to keep trying, knowing that your brain’s predictions are often overly pessimistic.");
        data.put("CBT-123", "【Small Steps Principle】When a task feels too big, we often avoid it entirely. The small steps principle is about breaking a task down until it feels manageable—even tiny. To apply this, if you need to clean the house, start with just one drawer. If you need to exercise, just put on your sneakers. The goal isn't to finish the whole thing, but just to start the first tiny step. Success on that small step builds momentum and self-efficacy, making the next step feel much easier. Remember, you don't need the energy for the whole mountain, just for the first few yards.");
        data.put("CBT-124", "【Overcoming Avoidance】Avoidance is the fuel that keeps anxiety and depression alive. It provides short-term relief but makes things harder in the long run. To apply a change, identify one thing you’ve been avoiding. Ask yourself: what is the smallest, easiest way I could face this today? By slowly and gently approaching the things we fear or dislike, we learn that we can handle them. This builds our confidence and shrinks the problem. Each time you choose action over avoidance, you are reclaiming a piece of your life and showing yourself that you are stronger than your discomfort.");
        data.put("CBT-125", "【Obstacle Identification】Sometimes we want to be active, but something keeps getting in the way. Obstacle identification involves looking ahead and spotting the things that might stop you from following your plan. To apply this, ask: what might get in the way of my walk today? If the answer is rain, your plan could be to walk at the mall instead. By having a plan B ready, you remove the power of the obstacle. This proactive thinking makes it much more likely that you'll stick to your goals, helping you build a consistent and rewarding routine regardless of what life throws at you.");
        data.put("CBT-126", "【Mastery Activities】Mastery activities are things that give you a sense of accomplishment, even if they aren't necessarily fun. This could be doing the dishes, paying a bill, or learning a new word. To apply this, include at least one mastery activity in your daily schedule. Feelings of depression often come with a sense of being useless or stuck. Doing something that makes you feel capable—no matter how small—is a powerful antidote. Mastery builds your self-esteem and reminds you that you have the power to influence your environment and take care of your life, which is a huge mood booster.");
        data.put("CBT-127", "【Pleasure Activities】Pleasure activities are things you do just because they feel good, like watching a sunset, taking a warm bath, or listening to music. To apply this, make a list of things that have given you joy in the past, even if they don't seem appealing right now. Aim to do one thing from this list every day. These activities help recharge your emotional battery and remind you that there is still beauty and comfort in the world. Even if the pleasure is small at first, consistently making space for joy is a vital part of maintaining long-term mental health.");
        data.put("CBT-128", "【The 5-Minute Rule】If you’re struggling to start something, commit to doing it for just five minutes. To apply this, tell yourself you can stop after five minutes if you want to. Usually, the hardest part is the transition from doing nothing to doing something. Once you've started, you'll often find you have the momentum to keep going. If you truly want to stop after five minutes, that's okay—you still succeeded in starting! This rule lowers the barrier to action and helps you overcome the paralyzing feeling of being overwhelmed, making even the most daunting tasks feel approachable.");
        data.put("CBT-129", "【Social Activation】When we feel bad, we often withdraw from others, but social connection is one of the best ways to improve our mood. To apply social activation, plan one small social interaction this week. It doesn't have to be a big party; it could be a quick text to a friend or a 10-minute coffee. Focus on the connection, not the performance. Being with others reminds us that we are part of a community and helps us get out of our own heads. Even small social wins can significantly reduce feelings of isolation and boost our sense of belonging and well-being.");
        data.put("CBT-130", "【Routine Building】A consistent routine provides a sense of structure and safety, which is especially helpful when life feels chaotic or your mood is low. To apply this, try to do basic things like waking up, eating, and sleeping at the same time each day. You don't need a complicated schedule; just a few anchor points in your day can make a big difference. Structure reduces the number of decisions you have to make, which saves your mental energy for more important things. A steady routine helps your body and mind stay balanced and makes it easier to navigate through difficult emotional times.");
        data.put("CBT-131", "【Values-Based Action】Sometimes we don't feel like doing anything, but we can still act based on our values. If you value being a good friend, you can send a birthday text even if you're tired. To apply this, identify three core values. When you’re stuck, ask: what is one small thing I can do right now that aligns with my values? This gives your actions a deeper meaning beyond just feeling good. Acting on your values builds a sense of integrity and purpose, which is a more stable source of satisfaction than waiting for a fleeting mood or burst of motivation to arrive.");
        data.put("CBT-132", "【The Action-First Mindset】Many people believe we need to feel motivated before we can act. Behavioral activation flips this: we often need to act before we feel motivated. To apply this, stop waiting for the right mood to strike. Treat your planned activities like a doctor's appointment—something you do because it's good for you, regardless of how you feel in the moment. Once you start moving, the motivation often follows. By shifting to an action-first mindset, you take control of your day away from your moods and put it back into your own hands, leading to more consistent progress.");
        data.put("CBT-133", "【Environment Tweaking】Your surroundings have a big impact on your behavior. If you want to exercise, put your clothes out the night before. If you want to avoid social media, put your phone in another room. To apply this, look for small ways to make the things you want to do easier and the things you want to avoid harder. Tweaking your environment reduces the amount of willpower you need to use. It’s like setting yourself up for success. Small changes in your physical space can lead to big changes in your daily habits and your overall mental well-being.");
        data.put("CBT-134", "【Celebrating Completion】When you finish a task, no matter how small, take a second to acknowledge it. To apply this, give yourself a mental high-five or check it off your list with a flourish. This small act of celebration releases a tiny bit of dopamine, which makes you feel good and encourages you to do more. We often rush to the next thing without appreciating what we've just done. By pausing to celebrate, you are training your brain to notice your competence and productivity. Over time, this builds a much more positive and energized self-image that is ready to take on the day.");
        data.put("CBT-135", "【Energy Accounting】Think of your energy like a bank account. Some activities are deposits (they give you energy), and some are withdrawals (they take energy). To apply this, look at your schedule and try to balance your energy. If you have a big withdrawal (like a stressful meeting), try to follow it with a deposit (like a quiet walk or a snack). Being aware of your energy levels helps you avoid burnout and ensures you have enough in the tank for the things that matter. It’s a practical way to manage your well-being and stay steady throughout the week.");
        data.put("CBT-136", "【Graded Task Assignment】If a goal feels impossible, use graded task assignment to build up to it. If your goal is to go back to school, start by just looking at one website for ten minutes. The next day, look at two. To apply this, create a ladder of steps toward your goal. Each step should be only slightly harder than the last. This gradual approach prevents you from being overwhelmed and allows you to build your skills and confidence along the way. By the time you reach the top of the ladder, the big goal will feel like a natural next step rather than a terrifying leap.");
        data.put("CBT-137", "【Mindful Engagement】When you're doing an activity, try to be fully present in it. If you're washing the dishes, notice the warm water and the bubbles. To apply this, use your senses to stay connected to the task at hand. Mindful engagement turns even mundane chores into a form of meditation. It prevents your mind from wandering to worries or regrets, which often happen when we are on autopilot. By being fully present, you get more out of your activities and find a sense of peace and flow in your daily life, making everything feel a bit more manageable and meaningful.");
        data.put("CBT-138", "【Identifying Natural Reinforcers】A natural reinforcer is a positive result that comes directly from your action, like the feeling of fresh air when you walk outside. To apply this, start noticing these good feelings as they happen. Don't just focus on finishing; focus on what you're getting out of the process. Noticing these natural rewards makes it much easier to stay motivated in the future. It’s like discovering hidden treasures in your daily routine. By paying attention to the good things that happen when you're active, you're reinforcing the habit of being active, making it much more likely to stick over time.");
        data.put("CBT-139", "【The Power of Variety】Doing the same things every day can lead to boredom and a low mood. To apply variety, try to mix up your activities. Even small changes, like taking a different route to work or trying a new fruit, can wake up your brain and make you feel more engaged. New experiences create new neural pathways and can provide unexpected sources of joy. By intentionally adding variety to your life, you stay curious and open to the world. It’s a simple way to keep your life feeling fresh and interesting, which is a great boost for your overall mental energy and mood.");
        data.put("CBT-140", "【Self-Contracting】Sometimes it helps to make a formal agreement with yourself. To apply self-contracting, write down a specific goal and a small reward you'll give yourself for completing it. For example, If I finish my filing, I can watch 30 minutes of my favorite show. Writing it down makes it feel more real and committed. The reward provides an extra bit of motivation to get through a difficult or boring task. It’s a way of treating yourself like a valued partner. By honoring your contracts with yourself, you build a sense of self-trust and reliability that is essential for a healthy, confident life.");
        data.put("CBT-141", "【Visual Reminders】Our brains are very visual. To apply this, place reminders of your goals and activities where you can see them. This could be a sticky note on the mirror, a picture on your fridge, or even a specific object that reminds you to stay mindful. Visual cues act as gentle nudges that keep your intentions at the front of your mind. They help you stay on track without having to rely solely on your memory or willpower. By surrounding yourself with positive reminders, you create an environment that supports your mental health and encourages you to keep moving toward the life you want.");
        data.put("CBT-142", "【The 'Just For Today' Mindset】When the future feels overwhelming, use the just for today mindset. To apply this, tell yourself: just for today, I will do my best to be active. You don't have to worry about tomorrow or next week; just focus on getting through this one day. This narrows your focus and makes your goals feel much more reachable. It’s like breaking time itself into small steps. By taking it one day at a time, you reduce your anxiety and make it easier to stay consistent. Success today builds the foundation for a better tomorrow, but for now, today is all that matters.");
        data.put("CBT-143", "【Pairing Activities】Pairing involves doing something you find difficult or boring alongside something you enjoy. To apply this, listen to a favorite podcast while you clean, or call a friend while you're walking. The positive activity makes the harder one feel less like a chore. It’s a great way to build new habits and get things done without it feeling like a struggle. By combining pleasure with productivity, you make your day more enjoyable and less draining. It’s a smart way to manage your energy and ensure you’re getting the most out of your time and effort every day.");
        data.put("CBT-144", "【Anchoring Your Activities】Anchor your new activities to things you already do. To apply this, if you want to practice deep breathing, do it every time you brush your teeth. If you want to drink more water, have a glass every time you check your email. These existing habits act as a hook for your new ones. This makes it much easier to remember and integrate new behaviors into your life. By using the structure you already have, you build a more supportive and healthy routine with much less effort, helping you stay consistent and see progress more quickly in your well-being journey.");
        data.put("CBT-145", "【The Accomplishment List】At the end of each day, write down three things you accomplished, no matter how small. To apply this, focus on the fact that you did them, regardless of how you felt. Maybe you did the laundry even though you were tired, or you were patient with a difficult person. This list provides physical proof of your competence and resilience. It shifts your focus from what you didn't do to what you did. Celebrating these daily wins builds a sense of pride and momentum. It reminds you that you are a capable person who is making progress, even on the tough days.");
        data.put("CBT-146", "【Reframing Chores as Self-Care】We often see household tasks as burdens, but they can also be seen as acts of self-care. To apply this, try to see cleaning your room as creating a peaceful space for yourself, or cooking as nourishing your body. This shift in perspective changes the energy of the task. Instead of I have to, it becomes I am doing this for me. Reframing chores as kindness to yourself makes them feel more meaningful and less draining. It’s a beautiful way to integrate self-support into your daily routine and treat your environment with the same care you are giving to your mind.");
        data.put("CBT-147", "【Social Support for Action】It’s often easier to be active when we do it with someone else. To apply this, find an accountability partner—a friend or family member who can join you in your walk or check in on your progress. Knowing someone else is watching or waiting for you provides a powerful extra bit of motivation. It also adds a social element to your activities, which is a double win for your mood. By sharing your goals with others, you build a supportive community that encourages you to stay active and healthy, making the whole process much more enjoyable and sustainable.");
        data.put("CBT-148", "【The Power of Starting Over】If you have a day where you aren't active or things don't go as planned, remember that you can always start over. To apply this, don't let a bad morning ruin the whole day, and don't let a bad day ruin the whole week. Every moment is a new chance to make a different choice. Treat yourself with the same kindness you'd show a friend who slipped up. Shrugging off a setback and trying again is a key part of resilience. The goal isn't to be perfect; it's to keep moving forward. You always have a fresh start available, right now.");
        data.put("CBT-149", "【Body-Lead Activation】When your mind is saying no, try to let your body lead. To apply this, instead of debating with your thoughts, just physically move your body toward the task. If you need to get out of bed, count 5-4-3-2-1 and just stand up before your brain can come up with excuses. This physical movement can bypass the mental barriers of depression or anxiety. It’s a practical way to get things done when your motivation is low. By letting your body take the first step, you often find that your mind eventually follows along, and the task becomes much easier than you expected.");
        data.put("CBT-150", "【Finding Your 'Why'】Understanding why an activity is important to you can provide the extra motivation you need to get started. To apply this, for each task on your schedule, ask: how does this help me? Maybe a clean desk helps you focus, or a walk makes you feel more connected to nature. Knowing your why gives the task a purpose and makes it feel more rewarding. It moves you from just going through the motions to acting with intention. Connecting your daily actions to your bigger goals and values is a powerful way to stay motivated and find satisfaction in everything you do.");
        data.put("CBT-151", "【Worry Time Technique】If you find yourself worrying all day, try scheduling a specific worry time. To apply this, choose 15 minutes a day to sit and think about all your concerns. If a worry pops up outside this time, tell yourself, I'll think about that during my worry time, and then return to your day. This gives you control over your anxiety rather than letting it control you. It shows you that you can acknowledge your worries without letting them take over your whole life. By containing your worry, you free up the rest of your day for more productive and enjoyable things.");
        data.put("CBT-152", "【Exposure Hierarchy】An exposure hierarchy is a way to face your fears in small, manageable steps. To apply this, list things related to your fear from least scary to most scary. If you're afraid of social situations, step one might be making eye contact with a cashier, and step ten might be giving a speech. Start at the bottom and only move up when you feel comfortable. This gradual approach teaches your brain that the situations aren't as dangerous as they feel. It builds your confidence and shrinks your fear over time, allowing you to reclaim your life from anxiety at your own pace.");
        data.put("CBT-153", "【Acceptance (ACT Principle)】Acceptance is the core of Acceptance and Commitment Therapy (ACT). It involves opening up to your anxious thoughts and feelings rather than trying to push them away. To apply this, when anxiety hits, try saying, I see you, anxiety. You're here right now, and that's okay. Pushing against anxiety often makes it grow stronger. By accepting it, you take away its power to fight you. You realize that you can be anxious and still do the things that matter to you. Acceptance isn't about giving up; it's about making peace with your internal weather so you can still go about your day.");
        data.put("CBT-154", "【Identifying Safety Behaviors】Safety behaviors are things we do to try to prevent anxiety or bad outcomes, like checking our phone in a crowd or always sitting near the exit. To apply a change, identify your safety behaviors and try to slowly let them go. While they feel helpful in the short term, they actually keep your anxiety alive by convincing you that you only survived because of the behavior. By facing situations without your safety net, you learn that you are actually safe and capable on your own. Releasing these behaviors is a huge step toward true confidence and freedom from anxiety.");
        data.put("CBT-155", "【The Worry Tree】The worry tree is a tool to help you decide what to do with a worry. To apply this, ask: Is this a problem I can do something about right now? If yes, make a plan and do it. If no, realize that worrying won't help, and let the thought go. This simple decision tree prevents you from getting stuck in a loop of useless worry. It helps you focus your energy on practical problem-solving while practicing the art of letting go for everything else. Using the worry tree brings a sense of clarity and efficiency to your thinking, reducing the overall noise of anxiety.");
        data.put("CBT-156", "【Mindful Acceptance of Uncertainty】Anxiety is often a struggle against the unknown. To apply mindful acceptance, practice sitting with the feeling of not knowing. Instead of seeking reassurance, try saying, I don't know what will happen, and I am okay right now. Life is inherently uncertain, and trying to control the future is exhausting. By accepting uncertainty, you build a deep sense of resilience and flexibility. You learn that you can handle whatever comes, which is a much more powerful and stable form of security than trying to predict and prevent every possible problem before it even happens.");
        data.put("CBT-157", "【Defusion (ACT Principle)】Cognitive defusion is the practice of seeing your thoughts as just words or images, not as absolute facts. To apply this, when a thought like I'm going to fail pops up, try saying it in a silly voice or singing it to a happy tune. This breaks the thought's power and reminds you that you don't have to take it seriously. You are the one watching the thoughts, not the thoughts themselves. Defusion creates a healthy distance between you and your mind, allowing you to choose which thoughts to follow and which ones to just let pass by like background noise.");
        data.put("CBT-158", "【Value-Driven Anxiety Management】Anxiety often shows up when we are doing something that matters to us. To apply this perspective, try to see your anxiety as a sign that you care. Instead of fighting it, say, I'm anxious because this is important to me, and I'm going to do it anyway. Shifting your focus from reducing anxiety to pursuing your values changes the whole experience. You move from a state of avoidance to a state of purpose. When your values are the driver and anxiety is just a passenger, you can still reach your destination, even if the ride is a bit bumpy.");
        data.put("CBT-159", "【The Worry Record】A worry record is a place to track your worries and see if they actually come true. To apply this, write down your prediction, and then come back a week later to see what actually happened. Most people find that their worries either don't happen or are much easier to handle than they expected. This record provides objective proof that your anxiety is often a poor predictor of the future. Seeing the evidence in black and white helps you trust your mind less when it tries to scare you, making it easier to stay calm and grounded in reality.");
        data.put("CBT-160", "【Anchoring in the Present】Anxiety is almost always about the future. To manage it, practice pulling your attention back to the present moment. To apply this, notice your physical sensations right now—the feeling of your chair, the temperature of the room, the sounds around you. By staying firmly in the here and now, you realize that in this exact second, you are okay. The future disaster isn't happening yet. This anchoring provides a safe harbor from the waves of worry about what might happen. It reminds you that you only ever have to handle this one present moment, which you are already doing!");
        data.put("CBT-161", "【Challenging Reassurance Seeking】Reassurance seeking is when we constantly ask others if things will be okay to lower our anxiety. While it works for a minute, it actually makes anxiety worse in the long run because we don't learn to reassure ourselves. To apply this, when you feel the urge to ask for reassurance, try to wait for ten minutes. Use that time to practice self-soothing or acceptance. By slowly reducing your dependence on others for safety, you build your own inner strength. You learn that you can handle the feeling of uncertainty on your own, which is the true path to lasting confidence.");
        data.put("CBT-162", "【The 'So What?' Technique】Anxiety often stops at the first scary thought. To challenge it, ask 'So what?'. If I mess up this speech, so what? Then people might think I'm nervous. So what? Then they'll move on and forget about it in five minutes. To apply this, keep asking until you reach a conclusion you can handle. Usually, the 'so what?' reveals that even the worst-case scenario isn't as life-ending as your anxiety made it feel. It helps you see the reality of the situation and realize that you have the skills to cope with whatever the actual outcome might be.");
        data.put("CBT-163", "【Normalizing Anxiety】Anxiety is a normal, healthy human emotion designed to keep us safe. To apply this, instead of thinking something is wrong with you, try saying, This is just my body's alarm system doing its job. It’s a bit too sensitive right now, but it’s not my enemy. Normalizing the feeling reduces the panic that often follows the first sign of anxiety. When you stop being afraid of the fear itself, it loses much of its power. You can learn to live with your alarm system, thanking it for its concern while choosing to stay calm because you know you are actually safe.");
        data.put("CBT-164", "【The Power of Breath in Anxiety】Anxiety often leads to shallow chest breathing, which signals to your brain that there's an emergency. To apply a fix, intentionally switch to slow, deep belly breaths. To apply this, place your hand on your stomach and make sure it rises with every inhale. This simple physical change can interrupt the anxiety cycle by sending a direct signal to your nervous system that it’s okay to calm down. It is one of the fastest ways to lower your heart rate and bring your mind back to a state of clarity. It’s your body’s built-in reset button for stress and worry.");
        data.put("CBT-165", "【Anxiety as Energy】Anxiety and excitement feel very similar in the body—both involve a fast heart rate and a sense of alertness. To apply this, try reframing your anxiety as energy for the task at hand. Instead of I'm nervous, try saying I'm energized or I'm ready. This small shift in labeling can change how you experience the physical sensations. Instead of something to be feared, the energy becomes something that can help you perform better. It moves you from a state of being overwhelmed to a state of being prepared, allowing you to use that extra energy to your advantage.");
        data.put("CBT-166", "【The 'Wait and See' Approach】When anxiety tells you to act immediately to fix a worry, try the wait and see approach. To apply this, tell yourself, I’m not going to do anything about this for the next hour. I’ll just wait and see how I feel then. Often, the intensity of the anxiety will drop on its own if you don't feed it with action. This approach teaches you that you don't have to react to every alarm your mind sets off. By delaying your response, you give yourself the space to choose a more logical and effective way to handle the situation later.");
        data.put("CBT-167", "【Self-Talk for Anxiety】The way you talk to yourself during an anxious moment can make a huge difference. To apply this, develop a few calming phrases to use when things get tough. Try saying, This is just a feeling, it will pass, or I am safe and I can handle this. Speak to yourself with the same calm, supportive voice you would use for a frightened child. This internal kindness provides a sense of safety that can quiet the noise of worry. By becoming your own source of comfort, you build a steady foundation of peace that you can carry with you into any situation.");
        data.put("CBT-168", "【Expanding Your Focus】Anxiety creates tunnel vision, where you only see the threat. To manage it, practice intentionally expanding your focus. To apply this, look around and notice the things that are going well, or even just the neutral things like the color of the walls or the feeling of the sun. By widening your perspective, you remind your brain that the worry is only one small part of your current reality. This reduces the dominance of the anxious thought and helps you feel more balanced and connected to the world around you, which is often much safer than your mind is telling you.");
        data.put("CBT-169", "【The Value of Courage】Courage isn't the absence of fear; it's doing something even though you're afraid. To apply this, celebrate your moments of courage. Every time you face an anxious situation, tell yourself, I was brave today. This builds a new identity for yourself—not as an anxious person, but as a courageous one. Focusing on your strength rather than your fear changes your self-image and makes you more willing to take on new challenges. Over time, these acts of courage build a life that is defined by your choices and values, not by the things you were too afraid to do.");
        data.put("CBT-170", "【Reviewing Past Successes】Anxiety loves to tell you that you can't handle things. To challenge this, take a minute to review all the hard things you've handled in the past. To apply this, think of three times you were worried but things turned out okay, or times you were stressed but you found a way through. This historical evidence is a powerful antidote to anxiety's lies. It reminds you that you have a 100% success rate of getting through your difficult days so far. Trusting your past self to support your present self builds a deep sense of confidence and inner peace.");
        data.put("CBT-171", "【Self-Compassion vs. Self-Criticism】Self-criticism is the habit of being harsh and judgmental with yourself, while self-compassion is treating yourself with the same kindness you'd show a friend. To identify criticism, listen for words like stupid, failure, or I should have. To apply compassion, try to replace those thoughts with understanding: I'm having a hard time, and it's okay to feel this way. Research shows that compassion actually makes us more resilient and motivated than criticism. Being kind to yourself isn't being soft; it's giving yourself the emotional fuel you need to learn, grow, and keep going through life's challenges.");
        data.put("CBT-172", "【Identifying Core Beliefs】Core beliefs are the fundamental ideas we hold about ourselves, others, and the world. They are often formed in childhood and act like a lens through which we see everything. Examples include I'm unlikable or The world is dangerous. To apply this, look at the patterns in your negative thoughts. What is the common theme? Once you identify a core belief, you can start to question it. Is it really true, or is it just a story you've been told? Identifying the root of your thinking is the first step toward changing the whole tree of your self-perception.");
        data.put("CBT-173", "【Challenging 'I'm Not Enough'】The belief that you are fundamentally not enough is one of the most common and painful core beliefs. To identify this, notice when you feel a sense of shame or a need to constantly prove yourself. To apply a fix, look for evidence of your inherent worth that isn't tied to your achievements. You are enough simply because you exist as a human being. Practice saying, My worth is not a result, it is a starting point. By separating your value from your performance, you create a stable sense of self-esteem that can't be taken away by a bad day or a mistake.");
        data.put("CBT-174", "【Building Positive Beliefs】Changing a negative belief is easier if you replace it with a positive one. Instead of I'm a failure, try I am someone who is learning and growing. To apply this, look for evidence every day that supports your new belief. Did you learn something today? Then you are growing! These small data points eventually build a new, stronger core belief. It’s like planting a new seed and watering it with attention. Over time, your positive beliefs will become your new default, leading to a much more supportive and energized internal world that helps you thrive in everything you do.");
        data.put("CBT-175", "【The Three Elements of Self-Compassion】Self-compassion has three parts: kindness (being gentle with yourself), common humanity (realizing everyone struggles), and mindfulness (noticing your pain without being overwhelmed). To apply this, when you're suffering, try to use all three. Say, I'm hurting (mindfulness), this is part of being human (common humanity), and I'm here for myself (kindness). This structured approach helps you stay balanced and connected during difficult times. It prevents the isolation and shame that often follow a struggle, reminding you that you are part of a kind, imperfect world where everyone is doing their best to find their way.");
        data.put("CBT-176", "【Identifying Your Inner Critic】We all have an inner critic—that voice in our head that tells us we're doing it wrong. To apply this technique, try to notice when the critic is speaking. What does it sound like? What are its favorite things to say? By identifying the critic as a separate part of your mind, you realize that its voice is not the final truth. You can choose to listen to a different, more compassionate voice instead. Treating your critic like a grumpy but well-meaning advisor who is just trying to protect you makes it much easier to ignore its harsher comments and stay focused on your goals.");
        data.put("CBT-177", "【Self-Worth vs. Self-Esteem】Self-esteem is often based on what we do and how we compare to others, but self-worth is the belief that we are valuable no matter what. To apply this shift, focus on your inherent worth. Achievements are great, but they aren't why you matter. You matter because of your capacity for kindness, your unique perspective, and your presence in the world. When your value is rooted in your worth rather than your esteem, you become much more resilient to the ups and downs of external success. You have an inner value that is steady, quiet, and always there for you to return to.");
        data.put("CBT-178", "【The Best Friend Test】When you're being hard on yourself, ask: would I say this to my best friend? To apply this, think about what you would actually say to them in your situation. You’d probably be supportive, understanding, and focused on how they can move forward. Now, try saying those exact things to yourself. This technique helps you access the natural kindness and wisdom you already have for others and turn it inward. Treating yourself like a best friend changes your entire internal atmosphere, making you feel more supported, capable, and ready to handle whatever life brings your way next.");
        data.put("CBT-179", "【Core Beliefs and the Filter】Core beliefs act like a filter that only lets in information that agrees with them. If you believe you're unlikable, you'll ignore ten smiles and focus on the one person who didn't look at you. To apply a change, start noticing your filter in action. Actively look for the information you've been filtering out—the evidence that you are loved, capable, and worthy. By intentionally widening your filter, you gather the data you need to challenge your old, negative beliefs and build a more accurate and positive view of yourself and the world around you.");
        data.put("CBT-180", "【The 'Good Enough' Goal】Perfectionism is a major enemy of self-compassion. To apply a change, try to aim for being good enough instead of perfect. To apply this, define what good enough looks like for a specific task. Maybe it's a finished project with a few minor flaws, or a home that's lived-in but comfortable. Embracing good enough allows you to be more productive and less stressed. It gives you the space to be a real human being who makes mistakes and learns from them. Realizing that good enough is actually great for most things leads to a much more peaceful and satisfying life.");
        data.put("CBT-181", "【Compassionate Letter Writing】Write a letter to yourself from the perspective of someone who loves you unconditionally. What would they say about your struggles, your strengths, and your worth? To apply this, read the letter whenever you're feeling particularly self-critical. Hearing your own life described through the eyes of love is a powerful way to shift your perspective. It helps you see yourself more clearly and kindly. This practice builds a deep sense of self-support and reminds you that you are worthy of love and care, both from others and, most importantly, from yourself.");
        data.put("CBT-182", "【Identifying Rules for Living】Rules for living are the intermediate beliefs between our core beliefs and our daily thoughts, often taking the form of If... then... statements. For example, If I'm always helpful, then people will like me. To apply this, look for the rules that are driving your stress. Are they realistic? Are they helpful? You have the right to change your rules. Try creating more flexible ones, like It’s good to be helpful, but it’s also okay to say no. Shifting your rules to be more balanced and kind makes your life feel much more manageable and authentically yours.");
        data.put("CBT-183", "【Celebrating Your Strengths】We often spend so much time fixing our weaknesses that we forget to celebrate our strengths. To apply this, make a list of five things you're good at, no matter how small. Maybe you're a good listener, you're organized, or you have a great sense of humor. Intentionally use these strengths every day. Focusing on what's right with you builds a sense of mastery and confidence. It reminds you that you have a lot to offer the world. By leaning into your strengths, you become more energized and effective, and your self-image becomes much more positive and resilient.");
        data.put("CBT-184", "【The Power of 'Yet'】When you're struggling with a skill, the word yet can be a powerful tool for self-compassion. Instead of saying I can't do this, try saying I can't do this yet. To apply this, use yet to remind yourself that you are a work in progress. It shifts your focus from a permanent failure to a temporary state of learning. This small addition creates space for growth and reduces the pressure to be an instant expert. It encourages you to keep trying, knowing that with time and effort, you can develop the skills and confidence you need to reach your goals.");
        data.put("CBT-185", "【Forgiving Your Past Self】We often carry around guilt for things we did or didn't do in the past. To apply self-compassion, try to forgive your past self. Remind yourself that you were doing the best you could with the tools and knowledge you had at the time. To apply this, say to yourself, I forgive you for X. I'm learning from it and moving forward. Letting go of past guilt frees up your energy for the present. It allows you to be the person you want to be now, rather than being stuck in a version of yourself that no longer exists. Forgiveness is a gift you give to yourself.");
        data.put("CBT-186", "【Self-Compassionate Journaling】Use your journal to practice kindness. At the end of the day, instead of just listing what went wrong, write about your day with compassion. Acknowledge the hard parts and give yourself credit for how you handled them. To apply this, ask: what would a kind observer say about my day today? This practice trains your brain to notice your efforts and your resilience. It builds a more balanced and supportive inner narrative. Over time, compassionate journaling becomes a powerful tool for self-healing and personal growth, helping you see yourself as a capable and worthy person.");
        data.put("CBT-187", "【Identifying Affirming Evidence】To challenge a negative core belief, you need to actively look for affirming evidence for a new, positive one. To apply this, keep a evidence log. Every time you do something well, or someone is kind to you, or you handle a challenge, write it down as proof of your worth and capability. We often dismiss these moments, but they are the building blocks of a new self-image. By intentionally focusing on and recording this affirming evidence, you slowly weaken the grip of your old beliefs and build a new, more positive foundation for your life and your self-worth.");
        data.put("CBT-188", "【The Importance of Self-Care】Self-care isn't a luxury; it's a vital part of self-worth and compassion. It’s the practice of taking care of your physical, emotional, and mental needs. To apply this, schedule regular self-care activities in your week. It could be a walk, a nap, a hobby, or just some quiet time. By treating yourself as someone worth taking care of, you are sending a powerful message to your brain about your value. Consistent self-care prevents burnout and keeps your emotional battery charged, allowing you to show up as your best self for both yourself and the people you care about most.");
        data.put("CBT-189", "【Compassion Toward Others】Interestingly, being compassionate toward others can help us be more compassionate toward ourselves. To apply this, practice noticing the common humanity in the people you meet. Everyone has their own struggles, fears, and hopes. To apply this, try to offer a small act of kindness or an understanding thought to someone else today. Seeing the world through a lens of compassion reduces judgment and makes the world feel like a safer, kinder place. This external kindness naturally reflects back onto yourself, making it easier to be gentle and supportive with your own internal struggles too.");
        data.put("CBT-190", "【Reframing Mistakes as Lessons】A mistake is only a failure if you don't learn from it. To apply self-compassion, try to reframe every mistake as a valuable lesson. To apply this, when you slip up, ask: what is this trying to teach me? This shift in perspective removes the sting of shame and replaces it with the energy of growth. It keeps you in a state of curiosity rather than judgment. By seeing mistakes as part of the natural learning process, you become much more willing to try new things and take healthy risks, leading to a richer and more fulfilling life full of growth and discovery.");
        data.put("CBT-191", "【The Self-Compassion Break】A self-compassion break is a quick mental practice for moments of stress. To apply it, stop and say: 1. This is a moment of suffering (mindfulness). 2. Suffering is a part of life (common humanity). 3. May I be kind to myself in this moment (kindness). This simple three-step process pulls you out of a spiral and gives you immediate emotional support. It’s like a warm hug for your mind. Using this break throughout the day keeps your stress levels manageable and reminds you that you are never alone in your struggles and that you are always worthy of your own care.");
        data.put("CBT-192", "【Identifying Cultural Beliefs】Many of our beliefs about ourselves come from our culture, family, or society. For example, the belief that we must be productive to be valuable. To apply this, look at your core beliefs and ask: where did this come from? Is this actually my belief, or is it something I was taught? Recognizing the external source of a belief makes it much easier to decide if you want to keep it or let it go. You have the right to define your own values and worth, regardless of what society tells you. Choosing your own beliefs is a powerful act of self-reclamation.");
        data.put("CBT-193", "【The Power of Positive Self-Talk】The way you talk to yourself creates your internal world. To apply this, practice using positive, encouraging language with yourself. Instead of I can't do this, try I'm doing my best and I'll find a way. This isn't about being unrealistic; it's about being your own coach. Positive self-talk builds confidence and reduces the impact of stress. It creates a supportive atmosphere where you feel safe to try, to fail, and to keep going. By intentionally choosing kind and powerful words, you are building a stronger, more resilient, and more joyful internal home for yourself every day.");
        data.put("CBT-194", "【Building a Support System】Self-worth is easier to maintain when you have a supportive community. To apply this, look for people who see your value and encourage your growth. To apply this, spend more time with those who lift you up and set healthy boundaries with those who bring you down. Having people who reflect your worth back to you is a great help when you're struggling to see it yourself. While your worth comes from within, being part of a kind and affirming network provides a safety net and a mirror that reminds you of your best self when you need it most.");
        data.put("CBT-195", "【The Art of Saying No】Saying no to things that drain you or don't align with your values is an act of self-worth. To apply this, practice setting clear, kind boundaries with your time and energy. You don't have to explain yourself or feel guilty for taking care of your needs. Saying no to one thing allows you to say yes to what truly matters—including your own well-being. By honoring your boundaries, you are showing yourself and others that your needs are important. This builds self-respect and ensures that you have the energy to show up fully for the things you truly care about.");
        data.put("CBT-196", "【Focusing on Your Path】It’s easy to feel inadequate when we compare our journey to others'. To apply self-compassion, practice focusing on your own path. Your journey is unique, with its own challenges, timing, and goals. To apply this, remind yourself that you are not in a race with anyone else. Your only goal is to be a bit better or kinder than you were yesterday. When you stop looking at everyone else's lane, you find more peace and energy for your own. Celebrating your own progress, no matter how it compares to others, leads to a much more authentic and satisfying life.");
        data.put("CBT-197", "【Acknowledging Your Bravery】It takes a lot of courage to face your thoughts and work on your mental health. To apply this, take a moment to acknowledge your own bravery. You are doing hard work that many people avoid. To apply this, say to yourself, I'm proud of myself for doing this work. Recognizing your own strength and commitment builds a sense of integrity and self-respect. It reminds you that you are a fighter and a seeker. This sense of pride provides the motivation you need to keep going, even when the work is difficult, knowing that you are building a better life for yourself.");
        data.put("CBT-198", "【The Compassionate Body Scan】Combine a body scan with self-compassion. As you move through your body, offer gratitude and kindness to each part. To apply this, thank your feet for carrying you, your heart for beating, and your mind for its creativity. If you find a part of your body you don't like, try to offer it extra kindness and understanding. This practice helps heal your relationship with your physical self and reduces body-related shame. By treating your body as a valued partner rather than an enemy, you build a deeper sense of wholeness and peace that supports your entire mental and physical well-being.");
        data.put("CBT-199", "【The 'I Am' Practice】Practice using positive 'I am' statements to reinforce your positive core beliefs. To apply this, choose three statements that feel true or that you want to be true, like I am capable, I am kind, or I am worthy of love. Repeat them to yourself every morning. While it might feel strange at first, these statements act as seeds that grow into new ways of thinking. By intentionally defining yourself in positive terms, you are reclaiming your identity from your old, negative beliefs and building a strong, vibrant sense of self that can weather any storm life brings your way.");
        data.put("CBT-200", "【Trusting the Process】Growth is not a straight line; it's a process with ups and downs. To apply self-compassion, practice trusting the process of your own evolution. To apply this, when you have a setback, remind yourself that it's a normal part of learning. You are still moving forward, even if it doesn't feel like it right now. Trusting the process allows you to stay patient and persistent. It reduces the pressure to see immediate results and helps you stay focused on the long-term journey of becoming your most authentic, healthy, and compassionate self. You are doing great, and the journey is worth it.");

        return data;
    }
}